const Service={path:"https://snpass.paulantezana.com/admin",apiPath:"https://snpass.paulantezana.com/admin"};class RequestApi{static setHeaders(e){return"POST"!==e.method&&"PUT"!==e.method&&"DELETE"!==e.method||(e.body instanceof FormData?e.headers={Accept:"application/json",...e.headers}:(e.headers={Accept:"application/json","Content-Type":"application/json; charset=utf-8",...e.headers},e.body=JSON.stringify(e.body))),e}static fetch(e,t){NProgress.start();const s=RequestApi.setHeaders({headers:{},...t}),a=Service.apiPath+e;return fetch(a,s).then(e=>(NProgress.done(),e.json())).catch(e=>(NProgress.done(),e))}static fetchText(e,t){const s=Service.apiPath+e;return NProgress.start(),fetch(s,t).then(e=>(NProgress.done(),e.text())).catch(e=>(NProgress.done(),e))}}